class Solution {
public:
    int maxProfit(vector<int>& prices) {
        if (prices.size() <= 1){
            return 0;
        }

        int minp = 9999999999;
        int maxp = 0;

        int best_p = 0;

        for (int val : prices){
            if (val > minp){
                maxp = val;
            }
            if (val < minp){
                minp = val;
                continue;
            }
            int temp = maxp - minp;
